    {
      "source_requirement": "Allows the user to select between full power and half power levels.",
      "rewritten_requirement": "The system shall allow the user to choose between full power and half power levels."
    },
    {
      "source_requirement": "Enables the user to set cooking time by entering a number.",
      "rewritten_requirement": "The system shall enable the user to set cooking time by entering a number."
    },
    {
      "source_requirement": "Stays inactive if the door is open during operation.",
      "rewritten_requirement": "The system shall remain inactive if the door is open during operation."
    },
    {
      "source_requirement": "Stops immediately when the door is opened during cooking process.",
      "rewritten_requirement": "The system shall stop immediately when the door is opened during the cooking process."
    },
    {
      "source_requirement": "Allows the user to cancel the cooking process.",
      "rewritten_requirement": "The system shall allow the user to cancel the cooking process."
    },
    {
      "source_requirement": "Returns to showing the time after stopping or cancelling and waits for next use.",
      "rewritten_requirement": "The system shall return to displaying the current time after stopping or cancelling and wait for the next use."
    }
  ]
}
```
